import '../../../core/channel/navivox_channel.dart';
import 'config_apply_flow_model.dart';

class ConfigApplyDispatcher {
  const ConfigApplyDispatcher();

  ConfigApplyDispatchResult dispatch({
    required ConfigApplyFlowModel flow,
    required NavivoxChannel channel,
  }) {
    if (!flow.hasPendingChanges) {
      return const ConfigApplyDispatchResult.skipped(
        'No pending config changes.',
      );
    }
    if (!flow.canApply) {
      return const ConfigApplyDispatchResult.skipped(
        'Config changes are invalid.',
      );
    }

    final appliedPaths = <String>[];
    for (final change in flow.changes) {
      if (change.isSecret) {
        channel.sendConfigSecretSet(
          name: change.path,
          secret: change.applyValue.toString(),
        );
      } else {
        channel.sendConfigSet(field: change.path, value: change.applyValue);
      }
      appliedPaths.add(change.path);
    }

    return ConfigApplyDispatchResult.dispatched(appliedPaths);
  }
}

class ConfigApplyDispatchResult {
  const ConfigApplyDispatchResult._({
    required this.appliedPaths,
    this.skippedReason,
  });

  const ConfigApplyDispatchResult.skipped(String reason)
    : this._(appliedPaths: const [], skippedReason: reason);

  factory ConfigApplyDispatchResult.dispatched(List<String> appliedPaths) {
    return ConfigApplyDispatchResult._(
      appliedPaths: List.unmodifiable(appliedPaths),
    );
  }

  final List<String> appliedPaths;
  final String? skippedReason;

  bool get wasDispatched => appliedPaths.isNotEmpty;
}

import '../serialization/navivox_json.dart';

/// Shared helpers for loose config-schema/validation wire maps.
///
/// Gormes config payloads may identify fields with related aliases depending on
/// whether the source is schema rows, validation errors, or section references.
/// These helpers keep alias lookup and non-empty string coercion consistent
/// across gateway protocol models and UI form models without broadening each
/// call site's accepted aliases.
String? configWireString(Object? raw) => navivoxOptionalStringFromJson(raw);

Object? configWireValueFromAliases(Map raw, Iterable<String> aliases) {
  for (final value in _configWireAliasCandidates(raw, aliases)) {
    if (value != null) return value;
  }
  return null;
}

String? configWireStringFromAliases(Map raw, Iterable<String> aliases) {
  for (final value in _configWireAliasCandidates(raw, aliases)) {
    final text = configWireString(value);
    if (text != null) return text;
  }
  return null;
}

List<String> configWireStringListFromAliases(
  Map raw,
  Iterable<String> aliases,
) {
  for (final value in _configWireAliasCandidates(raw, aliases)) {
    final list = navivoxStringListFromJson(value);
    if (list.isNotEmpty) return list;
  }
  return const [];
}

bool? configWireBoolFromAliases(Map raw, Iterable<String> aliases) {
  for (final value in _configWireAliasCandidates(raw, aliases)) {
    if (value is bool) return value;
  }
  return null;
}

Iterable<Object?> _configWireAliasCandidates(
  Map raw,
  Iterable<String> aliases,
) sync* {
  for (final alias in aliases) {
    if (raw.containsKey(alias)) yield raw[alias];
  }

  final normalizedAliases = {
    for (final alias in aliases) _configNormalizeWireFieldName(alias),
  };
  for (final entry in raw.entries) {
    if (normalizedAliases.contains(
      _configNormalizeWireFieldName('${entry.key}'),
    )) {
      yield entry.value;
    }
  }
}

String _configNormalizeWireFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

